import pytest

@pytest.mark.parametrize("scenario,amount,expected_status,expected_error", [
    ("valid", 1000, 202, None),
    ("insufficient_funds", 1000, 409, "INSUFFICIENT_FUNDS"),
    ("unverified_ach", 1000, 422, "ACH_LINK_NOT_VERIFIED"),
])
def test_ach_transfer_decision_table_all_conditions_matrix(
    scenario, amount, expected_status, expected_error,
    api_client, ach_scenario_fixture
):
    account_id, ach_id = ach_scenario_fixture(scenario)
    payload = {
        "source_account_id": account_id,
        "destination_ach_id": ach_id,
        "amount": amount,
        "currency": "USD"
    }
    resp = api_client.post("/transfers/ach", json=payload)
    assert resp.status_code == expected_status
    if expected_error:
        assert resp.json().get("error_code") == expected_error
